// ErrorCode represents API error codes
type ErrorCode string

const (
	CodeNotFound           ErrorCode = "NOT_FOUND"
	CodeInvalidRequest     ErrorCode = "INVALID_REQUEST"
	CodeUnauthorized       ErrorCode = "UNAUTHORIZED"
	CodeTimeout            ErrorCode = "TIMEOUT"
	CodeInternalError      ErrorCode = "INTERNAL_ERROR"
	CodeUpstreamError      ErrorCode = "UPSTREAM_ERROR"
	CodeJWTSigningFailed   ErrorCode = "JWT_SIGNING_FAILED"
	CodeServerOverloaded   ErrorCode = "SERVER_OVERLOADED"
	CodeSandboxUnreachable ErrorCode = "SANDBOX_UNREACHABLE"
	CodeConflict           ErrorCode = "CONFLICT"
	CodeValidationFailed   ErrorCode = "VALIDATION_FAILED"
)

// StatusError implements the APIStatus interface for error responses
type StatusError struct {
	ErrStatus metav1.Status
}

// Error implements the error interface
func (e *StatusError) Error() string {
	return e.ErrStatus.Message
}

// Status implements the APIStatus interface
func (e *StatusError) Status() metav1.Status {
	return e.ErrStatus
}

// NewNotFoundError creates a not found error
func NewNotFoundError(resource, name string) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusNotFound,
			Reason:  metav1.StatusReasonNotFound,
			Message: resource + " '" + name + "' not found",
		},
	}
}

// NewAlreadyExistsError creates an already exists error
func NewAlreadyExistsError(resource, name string) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusConflict,
			Reason:  metav1.StatusReasonAlreadyExists,
			Message: resource + " '" + name + "' already exists",
		},
	}
}

// NewInvalidError creates an invalid request error
func NewInvalidError(message string) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusBadRequest,
			Reason:  metav1.StatusReasonBadRequest,
			Message: message,
		},
	}
}

// NewUnauthorizedError creates an unauthorized error
func NewUnauthorizedError(message string) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusUnauthorized,
			Reason:  metav1.StatusReasonUnauthorized,
			Message: message,
		},
	}
}

// NewTimeoutError creates a timeout error
func NewTimeoutError(operation string) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusRequestTimeout,
			Reason:  metav1.StatusReasonTimeout,
			Message: "operation '" + operation + "' timed out",
		},
	}
}

// NewInternalError creates an internal server error
func NewInternalError(err error) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusInternalServerError,
			Reason:  metav1.StatusReasonInternalError,
			Message: err.Error(),
		},
	}
}

// NewUpstreamUnavailableError creates an upstream unavailable error
func NewUpstreamUnavailableError(service string) *StatusError {
	return &StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    http.StatusServiceUnavailable,
			Reason:  metav1.StatusReasonServiceUnavailable,
			Message: "upstream service '" + service + "' unavailable",
		},
	}
}

// IsNotFound checks if the error is a not found error
func IsNotFound(err error) bool {
	if err == nil {
		return false
	}
	if statusErr, ok := err.(*StatusError); ok {
		return statusErr.ErrStatus.Code == http.StatusNotFound
	}
	if err == ErrAgentRuntimeNotFound || err == ErrCodeInterpreterNotFound {
		return true
	}
	return false
}

// IsAlreadyExists checks if the error is an already exists error
func IsAlreadyExists(err error) bool {
	if err == nil {
		return false
	}
	if statusErr, ok := err.(*StatusError); ok {
		return statusErr.ErrStatus.Code == http.StatusConflict
	}
	return false
}

// IsTimeout checks if the error is a timeout error
func IsTimeout(err error) bool {
	if err == nil {
		return false
	}
	if statusErr, ok := err.(*StatusError); ok {
		return statusErr.ErrStatus.Reason == metav1.StatusReasonTimeout
	}
	if err == ErrSandboxCreationTimeout || err == ErrSandboxTimeout {
		return true
	}
	return false
}

// IsUnauthorized checks if the error is an unauthorized error
func IsUnauthorized(err error) bool {
	if err == nil {
		return false
	}
	if statusErr, ok := err.(*StatusError); ok {
		return statusErr.ErrStatus.Code == http.StatusUnauthorized
	}
	if err == ErrUnauthorized {
		return true
	}
	return false
}

// IsValidationError checks if the error is a validation error
func IsValidationError(err error) bool {
	if err == nil {
		return false
	}
	if statusErr, ok := err.(*StatusError); ok {
		return statusErr.ErrStatus.Code == http.StatusBadRequest
	}
	return false
}

// HTTPStatusFromError returns HTTP status code from error
func HTTPStatusFromError(err error) int {
	if err == nil {
		return http.StatusOK
	}
	if statusErr, ok := err.(*StatusError); ok {
		return int(statusErr.ErrStatus.Code)
	}
	if IsNotFound(err) {
		return http.StatusNotFound
	}
	if IsUnauthorized(err) {
		return http.StatusUnauthorized
	}
	if IsTimeout(err) {
		return http.StatusRequestTimeout
	}
	return http.StatusInternalServerError
}

