// RetryConfig configures retry behavior
type RetryConfig struct {
	MaxRetries     int
	BaseDelay      time.Duration
	MaxDelay       time.Duration
	RetryableCodes []int // HTTP status codes to retry
}

// DefaultRetryConfig returns default retry configuration
func DefaultRetryConfig() RetryConfig {
	return RetryConfig{
		MaxRetries: 3,
		BaseDelay:  1 * time.Second,
		MaxDelay:   30 * time.Second,
		RetryableCodes: []int{
			http.StatusServiceUnavailable, // 503
			http.StatusGatewayTimeout,     // 504
			http.StatusTooManyRequests,    // 429
		},
	}
}

// IsRetryableCode checks if the status code is retryable
func IsRetryableCode(statusCode int, retryableCodes []int) bool {
	for _, code := range retryableCodes {
		if statusCode == code {
			return true
		}
	}
	return false
}

// ExponentialBackoff returns exponential backoff duration
func ExponentialBackoff(baseDelay, maxDelay time.Duration, attempt int) time.Duration {
	if attempt <= 0 {
		return 0
	}

	delay := baseDelay
	for i := 1; i < attempt; i++ {
		delay *= 2
		if delay > maxDelay {
			return maxDelay
		}
	}
	return delay
}

// LinearBackoff returns linear backoff duration
func LinearBackoff(baseDelay time.Duration, attempt int) time.Duration {
	if attempt <= 0 {
		return 0
	}
	return baseDelay * time.Duration(attempt)
}

// FixedBackoff returns fixed backoff duration
func FixedBackoff(delay time.Duration) time.Duration {
	return delay
}

// DoRequestWithRetry executes a request with retry logic
func DoRequestWithRetry(
	client *http.Client,
	req *http.Request,
	config RetryConfig,
) (*http.Response, error) {
	var resp *http.Response
	var err error

	for attempt := 0; attempt <= config.MaxRetries; attempt++ {
		if attempt > 0 {
			delay := ExponentialBackoff(config.BaseDelay, config.MaxDelay, attempt)
			time.Sleep(delay)
		}

		resp, err = client.Do(req)
		if err != nil {
			if attempt == config.MaxRetries {
				return nil, fmt.Errorf("request failed after %d retries: %w", config.MaxRetries, err)
			}
			continue
		}

		if !IsRetryableCode(resp.StatusCode, config.RetryableCodes) {
			return resp, nil
		}

		resp.Body.Close()

		if attempt == config.MaxRetries {
			return nil, fmt.Errorf("request failed with status %d after %d retries", resp.StatusCode, config.MaxRetries)
		}
	}

	return resp, err
}

// RetryableFunc is a function that can be retried
type RetryableFunc func() error

// Retry retries the given function with exponential backoff
func Retry(fn RetryableFunc, config RetryConfig) error {
	var err error

	for attempt := 0; attempt <= config.MaxRetries; attempt++ {
		if attempt > 0 {
			delay := ExponentialBackoff(config.BaseDelay, config.MaxDelay, attempt)
			time.Sleep(delay)
		}

		err = fn()
		if err == nil {
			return nil
		}

		if attempt == config.MaxRetries {
			return fmt.Errorf("operation failed after %d retries: %w", config.MaxRetries, err)
		}
	}

	return err
}

