	DefaultHTTP2ReadTimeout    = 15 * time.Second
)

// NewHTTPTransport creates a configured transport
func NewHTTPTransport(config ClientConfig) *http.Transport {
	return &http.Transport{
		Proxy: http.ProxyFromEnvironment,
		DialContext: (&net.Dialer{
			Timeout:   30 * time.Second,
			KeepAlive: 30 * time.Second,
		}).DialContext,
		ForceAttemptHTTP2:     true,
		MaxIdleConns:          config.MaxIdleConns,
		IdleConnTimeout:       config.IdleConnTimeout,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		DisableCompression:    config.DisableCompression,
		MaxIdleConnsPerHost:   config.MaxIdleConnsPerHost,
		TLSClientConfig:       &tls.Config{InsecureSkipVerify: true},
	}
}

// NewHTTPClient creates an HTTP client with proper transport
func NewHTTPClient(config ClientConfig) (*http.Client, error) {
	transport := NewHTTPTransport(config)

	return &http.Client{
		Transport: transport,
		Timeout:   config.Timeout,
	}, nil
}

// NewHTTPClientWithH2C creates an HTTP client that supports h2c (HTTP/2 without TLS)
func NewHTTPClientWithH2C(config ClientConfig) (*http.Client, error) {
	transport := NewHTTPTransport(config)

	return &http.Client{
		Transport: transport,
		Timeout:   config.Timeout,
	}, nil
}

