func DefaultHTTPClient() *http.Client {
	config := DefaultClientConfig()
	client, _ := NewHTTPClient(config)
	return client
}

// TimeoutHTTPClient returns an HTTP client with timeout context
func TimeoutHTTPClient(parent context.Context, timeout time.Duration) (*http.Client, context.Context, context.CancelFunc) {
	ctx, cancel := context.WithTimeout(parent, timeout)
	client := DefaultHTTPClient()
	return client, ctx, cancel
}

// CloseIdleConnections closes idle connections for the client
func CloseIdleConnections(client *http.Client) {
	if client != nil && client.Transport != nil {
		if transport, ok := client.Transport.(*http.Transport); ok {
			transport.CloseIdleConnections()
		}
	}
}

